// src/tools/entity-tools.ts
function registerEntityTools(server, entityService) {
  server.tool(
    "imis_entity_list",
    "List entities from iMIS with optional filtering. Common types: Party (contacts/members), Event (conferences), Subscription (membership billing), Invoice/InvoiceSummary (amounts owed), Group (committees/chapters), Item (products), Gift/GiftSummary (donation history), and GiftInformationBatch (gift creation/import batches). Use imis_entity_types to discover all types. For complex queries spanning multiple tables, use imis_query (IQA) instead. Max 500 records per page.",
    {
      entityType: external_exports.string().describe("The entity type name (e.g., 'Party', 'Event', 'Invoice')"),
      limit: external_exports.number().min(1).max(500).optional().describe("Max records to return (default 100, max 500)"),
      offset: external_exports.number().min(0).optional().describe("Number of records to skip for pagination"),
      filter: external_exports.string().optional().describe("Filter as 'FieldName=value' pairs, comma-separated. Some entities require filters (e.g., EventRegistration needs EventId and PartyId)."),
      orderBy: external_exports.string().optional().describe("Sort results by field name. Prefix with '-' for descending (e.g., 'LastName', '-CreatedDate').")
    },
    withErrorHandling(async ({ entityType, limit, offset, filter, orderBy }) => {
      const params = {};
      if (filter) {
        for (const pair of filter.split(",")) {
          const [key, ...rest] = pair.trim().split("=");
          if (key && rest.length > 0) {
            params[key.trim()] = rest.join("=").trim();
          }
        }
      }
      let descending = false;
      let field;
      if (orderBy) {
        const parsed = parseOrderBy(orderBy);
        field = parsed.field;
        descending = parsed.descending;
      }
      const result = await fetchSortedWindow(
        (o) => entityService.list(entityType, o),
        { limit, offset, params, field, descending }
      );
      const items = result.items;
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify(
              { items, totalCount: result.totalCount, count: items.length },
              null,
              2
            )
          }
        ]
      };
    })
  );
  server.tool(
    "imis_entity_get",
    "Get a single entity by ID. Party IDs are numeric (e.g., '101'). Some entities use composite keys with ~ and | delimiters (e.g., EventRegistration: 'EventId~PartyId', GroupMember: '~GroupId|PartyId', Subscription: 'PartyId~ItemId'). Check imis_entity_types for ID format details.",
    {
      entityType: external_exports.string().describe("The entity type name (e.g., 'Party', 'Event')"),
      id: external_exports.string().describe("The entity ID")
    },
    withErrorHandling(async ({ entityType, id }) => {
      const result = await entityService.get(entityType, id);
      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
      };
    })
  );
  server.tool(
    "imis_entity_create",
    "Create a new entity in iMIS when the registry declares create support. IMPORTANT: When creating a Party, you MUST include '$type' field \u2014 use 'Asi.Soa.Core.DataContracts.PersonData, Asi.Contracts' for individuals or 'Asi.Soa.Core.DataContracts.InstitutionData, Asi.Contracts' for organizations. For EventRegistration, use imis_register_for_event instead (it uses the _execute endpoint). Raw finance/order/subscription/payment creates are reserved for purpose-built tools.",
    {
      entityType: external_exports.string().describe("The entity type name"),
      data: external_exports.string().describe("JSON string of the entity data to create")
    },
    withErrorHandling(async ({ entityType, data }) => {
      const parsed = JSON.parse(data);
      const result = await entityService.create(entityType, parsed);
      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
      };
    })
  );
  server.tool(
    "imis_entity_update",
    "Update an existing entity in iMIS (full PUT \u2014 sends entire entity). To change specific fields: GET the entity first, modify the fields you need, then PUT the full object back.",
    {
      entityType: external_exports.string().describe("The entity type name"),
      id: external_exports.string().describe("The entity ID to update"),
      data: external_exports.string().describe("JSON string of the fields to update")
    },
    withErrorHandling(async ({ entityType, id, data }) => {
      const parsed = JSON.parse(data);
      const result = await entityService.update(entityType, id, parsed);
      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
      };
    })
  );
  server.tool(
    "imis_entity_delete",
    "Delete an entity from iMIS. Some entities cannot be deleted (Invoices, Payments). For composite key entities, use the full composite ID (e.g., GroupMember: '~GroupId|PartyId').",
    {
      entityType: external_exports.string().describe("The entity type name"),
      id: external_exports.string().describe("The entity ID to delete")
    },
    withErrorHandling(async ({ entityType, id }) => {
      await entityService.delete(entityType, id);
      return {
        content: [{ type: "text", text: `Successfully deleted ${entityType} with ID "${id}".` }]
      };
    })
  );
  server.tool(
    "imis_entity_validate",
    "Validate entity data against iMIS rules without saving.",
    {
      entityType: external_exports.string().describe("The entity type name"),
      data: external_exports.string().describe("JSON string of the entity data to validate")
    },
    withErrorHandling(async ({ entityType, data }) => {
      const parsed = JSON.parse(data);
      const result = await entityService.validate(entityType, parsed);
      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
      };
    })
  );
  server.tool(
    "imis_entity_execute",
    "Execute a special operation via _execute endpoint. Key uses: EventRegistration (create a registration \u2014 use imis_register_for_event for convenience), OrganizationMerge (merge duplicate orgs). The _execute endpoint handles operations that don't fit standard CRUD patterns.",
    {
      entityType: external_exports.string().describe("The entity type name"),
      data: external_exports.string().describe("JSON string of the execution request data")
    },
    withErrorHandling(async ({ entityType, data }) => {
      const parsed = JSON.parse(data);
      const result = await entityService.execute(entityType, parsed);
      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
      };
    })
  );
  server.tool(
    "imis_entity_changelog",
    "Get the change history for an iMIS entity.",
    {
      entityType: external_exports.string().describe("The entity type name"),
      id: external_exports.string().describe("The entity ID")
    },
    withErrorHandling(async ({ entityType, id }) => {
      const result = await entityService.changelog(entityType, id);
      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
      };
    })
  );
}

