// src/tools/communications-tools.ts
function registerCommunicationsTools(server, entityService, iqaService) {
  server.tool(
    "imis_communications",
    `View communication history for a contact in iMIS. Shows emails, letters, and other communications sent to or logged against a member. Requires a Party ID filter \u2014 Communications cannot be listed globally.`,
    {
      partyId: external_exports.string().describe("Party ID of the contact"),
      limit: external_exports.number().optional().describe("Maximum results (default: 50)")
    },
    withErrorHandling(async ({ partyId, limit }) => {
      const historyLimit = limit ?? 50;
      const [preferences, history] = await Promise.all([
        readCommunicationPreferences(entityService, partyId),
        readCommunicationHistory(entityService, partyId, historyLimit, iqaService)
      ]);
      const evidence = [preferences.evidence, ...history.evidence];
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            partyId,
            status: communicationStatus(evidence),
            preferences: preferences.value,
            history: history.value,
            communications: history.value.communications,
            count: history.value.count,
            totalCount: history.value.totalCount,
            evidence,
            note: "Communication history first uses the server-filtered CommunicationLogRecipient endpoint by PartyId. If that endpoint is unavailable, the tool tries the Communication endpoint and then a bounded Communication log IQA fallback. Preference evidence comes from the Party record."
          }, null, 2)
        }]
      };
    })
  );
  server.tool(
    "imis_campaigns",
    `List or get fundraising campaigns, appeals, source codes, and solicitations in iMIS. Campaigns track fundraising initiatives; appeals are sub-segments; source codes track marketing channels; solicitations are outreach efforts. Core to fundraising analytics and donor segmentation.`,
    {
      action: external_exports.enum(["list_campaigns", "list_appeals", "list_sources", "list_solicitations", "get"]).describe("Action to perform"),
      id: external_exports.string().optional().describe("Record ID (required for 'get')"),
      entityType: external_exports.enum(["CampaignSummary", "AppealSummary", "SourceCodeSummary", "SolicitationSummary"]).optional().describe("Entity type for 'get' (required with 'get')"),
      limit: external_exports.number().optional().describe("Maximum results (default: 50)")
    },
    withErrorHandling(async ({ action, id, entityType, limit }) => {
      switch (action) {
        case "list_campaigns": {
          const result = await entityService.list("CampaignSummary", { limit: limit ?? 50 });
          return {
            content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
          };
        }
        case "list_appeals": {
          const result = await entityService.list("AppealSummary", { limit: limit ?? 50 });
          return {
            content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
          };
        }
        case "list_sources": {
          const result = await entityService.list("SourceCodeSummary", { limit: limit ?? 50 });
          return {
            content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
          };
        }
        case "list_solicitations": {
          const result = await entityService.list("SolicitationSummary", { limit: limit ?? 50 });
          return {
            content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
          };
        }
        case "get": {
          if (!id) throw new Error("'id' is required for get");
          if (!entityType) throw new Error("'entityType' is required for get");
          const result = await entityService.get(entityType, id);
          return {
            content: [{ type: "text", text: JSON.stringify(result, null, 2) }]
          };
        }
        default:
          throw new Error(`Unknown action: ${action}`);
      }
    })
  );
  server.tool(
    "imis_notifications",
    `View or manage notification set configurations in iMIS. Notification sets define automated email notifications triggered by events like membership renewal, event registration, or payment receipt. Use to check what automated communications are configured.`,
    {
      action: external_exports.enum(["list", "get"]).describe("'list' notification sets or 'get' one by ID"),
      notificationSetId: external_exports.string().optional().describe("Notification set ID (required for 'get')"),
      limit: external_exports.number().optional().describe("Maximum results (default: 50)")
    },
    withErrorHandling(async ({ action, notificationSetId, limit }) => {
      if (action === "get") {
        if (!notificationSetId) throw new Error("'notificationSetId' is required for get");
        const result2 = await entityService.get("NotificationSet", notificationSetId);
        return {
          content: [{ type: "text", text: JSON.stringify(result2, null, 2) }]
        };
      }
      const result = await entityService.list("NotificationSet", { limit: limit ?? 50 });
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            notificationSets: result.items,
            count: result.items.length,
            totalCount: result.totalCount
          }, null, 2)
        }]
      };
    })
  );
}

