// src/tools/hub-tools.ts
function compactText(value, max) {
  const normalized = value.replace(/\s+\n/g, "\n").replace(/[ \t]+/g, " ").trim();
  return normalized.length > max ? `${normalized.slice(0, max - 1)}...` : normalized;
}
function registerHubTools(server, companion) {
  server.tool(
    "imis_hub_outcome",
    `Relay a concise, sanitized workflow outcome to iFINITY AgentZ activity. Use this at the end of multi-tool investigations, when creating IQA/content artifacts, or when the important conclusion would otherwise exist only in the chat transcript. Include saved iMIS paths, document/version keys, preview counts, final recommendation, and unresolved proof gaps when relevant. Do not include secrets, access tokens, raw personal data dumps, or full API payloads.`,
    {
      title: external_exports.string().min(1).max(140).describe("Short outcome title for the AgentZ activity card."),
      summary: external_exports.string().min(1).max(1600).describe("Sanitized one- or two-paragraph summary of what was concluded."),
      details: external_exports.string().max(6e3).optional().describe("Optional sanitized details: paths, IDs, preview counts, selected records, proof gaps, and next steps."),
      artifactPath: external_exports.string().max(500).optional().describe("Optional saved iMIS artifact path, e.g. $/Common/Queries/CodexRE/Recent Event Registrations."),
      artifactType: external_exports.string().max(40).optional().describe("Optional artifact type such as IQD, CON, panel source, query, or content page."),
      documentId: external_exports.string().max(120).optional().describe("Optional iMIS DocumentId for the artifact."),
      documentVersionId: external_exports.string().max(120).optional().describe("Optional iMIS DocumentVersionId/DocumentVersionKey for the artifact."),
      status: external_exports.enum(["success", "working", "error"]).default("success").describe("AgentZ activity status.")
    },
    withErrorHandling(async ({
      title,
      summary,
      details,
      artifactPath,
      artifactType,
      documentId,
      documentVersionId,
      status
    }) => {
      const metadata = {};
      if (artifactPath) metadata.artifactPath = artifactPath;
      if (artifactType) metadata.artifactType = artifactType;
      if (documentId) metadata.documentId = documentId;
      if (documentVersionId) metadata.documentVersionId = documentVersionId;
      companion?.sendActivity(
        "agent_outcome",
        compactText(summary, 1600),
        status,
        {
          kind: "outcome",
          title: compactText(title, 140),
          details: details ? compactText(details, 6e3) : void 0,
          metadata
        }
      );
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            ok: true,
            relayedToHub: Boolean(companion?.isConnected()),
            title,
            artifactPath,
            artifactType,
            documentId,
            documentVersionId
          }, null, 2)
        }]
      };
    })
  );
}

