// src/tools/setup-tools.ts
function registerSetupTools(server, isConfigured, getConnectionInfo) {
  server.tool(
    "imis_connection_status",
    "Check iMIS API connection status \u2014 whether iFINITY AgentZ has provided an OAuth token.",
    {},
    async () => {
      if (!isConfigured()) {
        return {
          content: [{
            type: "text",
            text: JSON.stringify({
              status: "NOT_CONNECTED",
              message: "Waiting for iFINITY AgentZ to connect. Open AgentZ, sign in to iMIS, and set up the API connection."
            }, null, 2)
          }]
        };
      }
      const info = getConnectionInfo();
      return {
        content: [{
          type: "text",
          text: JSON.stringify({
            status: "CONNECTED",
            baseUrl: info.baseUrl,
            source: info.source
          }, null, 2)
        }]
      };
    }
  );
}

// src/resources/entity-resources.ts
function registerEntityResources(server, entityService) {
  server.resource(
    "entity-types",
    "imis://entities",
    { description: "List all available iMIS entity types grouped by category" },
    async () => {
      const categories = getAllCategories();
      const grouped = categories.map((cat) => ({
        category: cat,
        entities: getEntitiesByCategory(cat).map((e) => ({
          name: e.name,
          description: e.description,
          readOnly: e.readOnly ?? false
        }))
      }));
      return {
        contents: [
          {
            uri: "imis://entities",
            mimeType: "application/json",
            text: JSON.stringify(grouped, null, 2)
          }
        ]
      };
    }
  );
  const entityListTemplate = new ResourceTemplate(
    "imis://entities/{entityType}",
    { list: void 0 }
  );
  server.resource(
    "entity-list",
    entityListTemplate,
    { description: "List records of a specific iMIS entity type" },
    async (uri, variables) => {
      const typeName = variables.entityType;
      const result = await entityService.list(typeName, { limit: 50 });
      return {
        contents: [
          {
            uri: uri.href,
            mimeType: "application/json",
            text: JSON.stringify(
              { entityType: typeName, items: result.items, totalCount: result.totalCount },
              null,
              2
            )
          }
        ]
      };
    }
  );
  const entityDetailTemplate = new ResourceTemplate(
    "imis://entities/{entityType}/{id}",
    { list: void 0 }
  );
  server.resource(
    "entity-detail",
    entityDetailTemplate,
    { description: "Get a specific iMIS entity by type and ID" },
    async (uri, variables) => {
      const result = await entityService.get(
        variables.entityType,
        variables.id
      );
      return {
        contents: [
          {
            uri: uri.href,
            mimeType: "application/json",
            text: JSON.stringify(result, null, 2)
          }
        ]
      };
    }
  );
}

