// src/resources/instance-resources.ts
function registerInstanceResources(server, apiClient) {
  server.resource(
    "instances",
    "imis://config/instances",
    { description: "List configured iMIS instances (credentials redacted)" },
    async () => {
      const names = apiClient.getInstanceNames();
      const activeName = apiClient.activeInstance.name;
      const instances = names.map((name) => ({
        name,
        active: name === activeName,
        // Don't expose credentials
        baseUrl: name === activeName ? apiClient.activeInstance.baseUrl : "(switch to view)"
      }));
      return {
        contents: [
          {
            uri: "imis://config/instances",
            mimeType: "application/json",
            text: JSON.stringify({ instances }, null, 2)
          }
        ]
      };
    }
  );
  server.resource(
    "active-instance",
    "imis://config/active",
    { description: "Show the currently active iMIS instance" },
    async () => {
      const instance = apiClient.activeInstance;
      return {
        contents: [
          {
            uri: "imis://config/active",
            mimeType: "application/json",
            text: JSON.stringify(
              {
                name: instance.name,
                baseUrl: instance.baseUrl,
                grantType: instance.grantType
              },
              null,
              2
            )
          }
        ]
      };
    }
  );
}

