// src/prompts/presentation-guidance.ts
var COWORK_INLINE_PRESENTATION_GUIDANCE = `Cowork presentation rule: when running in Claude Cowork and the show_widget tool is available, present any iMIS result board, comparison, choice, audit, dashboard, or call-to-action matrix inline with show_widget. Include compact summary cards, evidence rows, and follow-up buttons for predictable actions. Do not use create_artifact as the primary Cowork surface for those boards. If show_widget is unavailable, keep the same structure in concise Markdown or ordinary files.`;
function withCoworkInlinePresentation(prompt) {
  return `${prompt}

${COWORK_INLINE_PRESENTATION_GUIDANCE}`;
}

// src/prompts/member-prompts.ts
function registerMemberPrompts(server) {
  server.prompt(
    "find-member",
    "Find a member in iMIS by name, email, or ID",
    { searchTerm: external_exports.string().describe("Name, email address, or Party ID to search for") },
    ({ searchTerm }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Find the iMIS member matching "${searchTerm}". Use the imis_find_member tool to search. If found, show their key details: name, email, member status, and organization. If multiple results, list them briefly and ask which one to view in detail.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "member-profile",
    "Get a complete member profile with all related data from iMIS",
    { partyId: external_exports.string().describe("The Party ID of the member") },
    ({ partyId }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Build a complete 360-degree profile for iMIS member with Party ID "${partyId}". Use these tools:
1. imis_entity_get Party ${partyId} \u2014 basic contact info (name, email, status, organization)
2. imis_billing_summary ${partyId} \u2014 subscriptions (membership status, dues), invoices (what they owe), payments (what they've paid)
3. imis_search GroupMember with PartyId=${partyId} \u2014 committee and chapter memberships
4. imis_search ContactInteraction with PartyId=${partyId} \u2014 recent activity/interaction history

In iMIS, a member is "active" if they have a Subscription where PaidThrough > today. Compile into a clear profile summary with sections: Contact Info, Membership Status, Billing, Groups/Committees, Recent Activity.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "member-360",
    "Party/member 360 view with source status \u2014 contact, billing, events, engagement, data quality",
    { partyId: external_exports.string().describe("The Party ID of the member") },
    ({ partyId }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Build a Party/member 360 view for iMIS member "${partyId}". Use imis_member_360 partyId="${partyId}" to pull the default API-backed sections in a single call. If the user needs communications, form responses, or custom panel data, request those sections explicitly with sections="communications,forms,customPanels". Compile into sections:

1. **Contact Info**: Name, email, organisation, address, member type
2. **Membership Status**: Subscription type, PaidThrough date, active/lapsed, join date
3. **Billing & Dues**: Outstanding invoices, recent payments, total balance
4. **Groups & Committees**: Chapter, committee, and section memberships with roles
5. **Giving History**: Total lifetime giving, recent gifts, pledge status
6. **Relationships**: Connected contacts (employer, spouse, etc.)
7. **Engagement & Recent Activity**: iMIS-native score result rows where available, plus interactions, groups, and subscriptions as raw signals
8. **Data Quality**: Duplicate candidate status and any required follow-up

Use the root Party360Contract as the single source of truth. Each section has status, summary, data, and sources; use the section status and sources when you need to explain what was queried, failed, not requested, not implemented, or requires native handoff. Do not claim coverage for omitted sections. Highlight key insights only from sections that were successfully queried: Is membership at risk (approaching expiry)? Are they a major donor? Are they actively engaged or disengaged? Any outstanding issues?`)
          }
        }
      ]
    })
  );
  server.prompt(
    "lapsing-members",
    "Identify members whose memberships are expiring soon",
    {
      daysUntilExpiry: external_exports.string().optional().describe("Number of days to look ahead (default: 30)")
    },
    ({ daysUntilExpiry }) => {
      const days = daysUntilExpiry ?? "30";
      return {
        messages: [
          {
            role: "user",
            content: {
              type: "text",
              text: withCoworkInlinePresentation(`Identify iMIS members whose memberships expire within the next ${days} days:

1. Use imis_entity_list Subscription with limit=200 to pull active subscriptions.
2. Filter for records where PaidThrough is between today and ${days} days from now. Use full ISO DateTime bounds when creating IQA filters, and verify preview rows actually fall inside the window before naming the cohort.
3. For each lapsing member, use imis_entity_get Party/{PartyId} to get contact details.
4. Present a table: Name | Email | Membership Type (ItemId) | PaidThrough Date | Days Until Expiry
5. Summarize: total count expiring, breakdown by membership type.
6. Check for any with outstanding invoices using imis_billing_summary.
7. Suggest renewal outreach actions \u2014 which members to prioritise.`)
            }
          }
        ]
      };
    }
  );
}

// src/prompts/event-prompts.ts
function registerEventPrompts(server) {
  server.prompt(
    "event-registration",
    "Guide through registering someone for an iMIS event",
    {
      partyId: external_exports.string().optional().describe("Party ID of the registrant (optional \u2014 will search if not provided)"),
      eventId: external_exports.string().optional().describe("Event ID to register for (optional \u2014 will list events if not provided)")
    },
    ({ partyId, eventId }) => {
      const steps = [];
      if (!eventId) {
        steps.push("1. Use imis_entity_list Event to show upcoming events and ask which one to register for.");
      }
      if (!partyId) {
        steps.push(`${steps.length + 1}. Ask for the registrant's name or email, then use imis_find_member to locate them.`);
      }
      steps.push(`${steps.length + 1}. Use imis_entity_list EventFunction with EventId filter to show available sessions/functions.`);
      steps.push(`${steps.length + 1}. Use imis_register_for_event to complete the registration.`);
      steps.push(`${steps.length + 1}. Confirm the registration was successful and show the details.`);
      return {
        messages: [
          {
            role: "user",
            content: {
              type: "text",
              text: withCoworkInlinePresentation(`Help register ${partyId ? `Party ${partyId}` : "a member"} for ${eventId ? `Event ${eventId}` : "an event"} in iMIS.

Steps:
${steps.join("\n")}`)
            }
          }
        ]
      };
    }
  );
  server.prompt(
    "event-report",
    "Generate an event registration report from iMIS",
    { eventId: external_exports.string().describe("The Event ID to report on") },
    ({ eventId }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Generate a registration report for iMIS Event "${eventId}":
1. Use imis_entity_get Event ${eventId} to get event details (name, dates, location, functions/sessions).
2. Note: EventRegistration and EventRegistrationSummary cannot be listed via standard queries. Try imis_query with a system IQA query path like $/Common/Queries/Events/EventRegistrations if available, or check for event-specific queries.
3. Summarize: event details, total registrants if available, session/function breakdown, any notable patterns.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "event-dashboard",
    "Generate an event dashboard \u2014 registrations, capacity, revenue, and status for one or all events",
    {
      eventId: external_exports.string().optional().describe("Specific Event ID (omit for overview of all upcoming events)")
    },
    ({ eventId }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(eventId ? `Generate an event dashboard for iMIS Event "${eventId}":
1. imis_entity_get Event/${eventId} \u2014 event details (name, dates, location, capacity, status)
2. imis_entity_list EventRegistrationSummary with filter EventId=${eventId} \u2014 registration list and count
3. imis_entity_list ItemPrice with filter ItemId=${eventId} \u2014 pricing tiers
4. Calculate: total registered, spots remaining (Capacity - registrations), estimated revenue
5. Present: event summary with key metrics, registration count vs capacity, revenue estimate, list of registrants` : `Generate an event overview dashboard from iMIS:
1. imis_entity_list Event with limit=50 \u2014 get all events (focus on Status=A for active)
2. imis_entity_list EventSummary \u2014 summary view with key fields
3. For the top 5 upcoming events, get registration counts via imis_entity_list EventRegistrationSummary with EventId filter
4. Present: table of upcoming events with Name, Dates, Status, Registration Count, Capacity, Spots Remaining`)
          }
        }
      ]
    })
  );
}

