// src/prompts/reporting-prompts.ts
function registerReportingPrompts(server) {
  server.prompt(
    "membership-report",
    "Generate a membership status report from iMIS",
    {},
    () => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Generate a membership status report from iMIS:
1. Use imis_entity_list Subscription to get subscriptions. In iMIS, membership is determined by Subscriptions \u2014 active members have PaidThrough dates in the future.
2. Use imis_entity_list GroupClassSummary to understand the group structure (committees, chapters).
3. If IQA queries are available, try imis_query with paths like $/Common/Queries/Membership/ for detailed membership analytics.
4. Summarize: total active members (PaidThrough > today), lapsed members (PaidThrough < today), membership tier breakdown by product code, chapter distribution.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "financial-summary",
    "Generate a financial summary from iMIS",
    {
      accountType: external_exports.string().optional().describe("GL account type to filter by")
    },
    ({ accountType }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Generate a financial summary from iMIS${accountType ? ` for account type "${accountType}"` : ""}:
1. Use imis_entity_list InvoiceSummary to get recent invoices (amounts owed).
2. Use imis_entity_list PaymentSummary to get recent payments received.
${accountType ? `3. Use imis_search GLAccount with AccountType=${accountType} to get relevant GL accounts.` : "3. Use imis_entity_list GLAccount to get GL accounts."}
4. If IQA queries are available, try imis_query with $/Common/Queries/Finance/ for detailed financial reports.
5. Summarize: total invoiced, total collected, outstanding balance, trends. Note that iMIS supports multiple Financial Entities (separate accounting books).`)
          }
        }
      ]
    })
  );
  server.prompt(
    "iqa-report",
    "Execute an IQA query and analyze the results",
    {
      queryPath: external_exports.string().describe("The IQA query path (e.g., $/Common/Queries/ContactManagement/AllContacts)"),
      description: external_exports.string().optional().describe("Description of what this query does")
    },
    ({ queryPath, description }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Run the IQA query "${queryPath}"${description ? ` (${description})` : ""} and analyze the results:
1. Use imis_query with queryPath="${queryPath}" to execute the query.
2. Examine the returned data structure and fields.
3. Provide a clear summary of the results with key statistics and patterns.
4. If the query has too many results, note the total count and suggest filtering with runtime parameters.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "iqa-build-plan",
    "Plan an IQA query/report workflow against the supported MCP and iMIS surfaces",
    {
      goal: external_exports.string().describe("Business reporting goal or query to design")
    },
    ({ goal }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Plan the IQA workflow for this goal: "${goal}".
1. Use imis_iqa_surface search with liveCheck=true to resolve broad intent to likely IQA sources or packaged query families.
2. Use imis_iqa_source_profile for each candidate Business Object or panel source, especially when the client may have custom fields. Match requested business terms to live property names before writing a design.
3. Use imis_iqa_content_plan when the goal crosses IQA, custom BO/panel data, content records, or iParts. Carry its display alias, filter, relation, and iPart recommendations into the rest of the workflow.
4. Use imis_iqd_query action="capabilities" only when you need the supported public query-form limits. Do not ask the agent to find or inspect an iMIS template; the MCP builder owns graph planning and serialization.
5. Search official iMIS help/dev docs for any IQA features involved: sources, relations, filters/prompts, Query endpoint parameters, templates, reports, alerts, dashboards, or content placement.
6. Browse existing queries under $/Common/Queries/ and reuse one if it already satisfies the goal.
7. If a new IQD shape is covered by the supported query form, use imis_iqd_query validate, assemble, then create with a limited preview. Use full ISO DateTime literals for date filters. Include templateHtml when Query Template Display output is needed.
8. If the workload needs page placement for existing IQDs or query folders, use imis_page_iparts action="add_query_menu"; use action="add_query_template" when the query has Template tab HTML.
9. For Query Template Display, verify that template placeholders use Display aliases, not raw BO property names.
10. If the backend rejects a relation, aggregation, SSRS, alert, navigation placement, PanelEditor/chart iPart shape, or custom BO write contract, do not attempt a manual document write. Use safe existing-query/read alternatives and report the exact backend validation message.
11. Use imis_hub_outcome to relay the final sanitized outcome to iFINITY AgentZ, including saved iMIS paths, document/version keys, preview counts, decision rationale, risks, and unresolved proof gaps. Keep raw API payloads, credentials, and unnecessary personal data out of the AgentZ relay.
12. Summarize with an agent handoff packet in chat: intent class, target surfaces, iMIS paths, document/version keys, source aliases, display aliases, iPart keys, preview/XML/browser evidence, per-document publish status, risks, unresolved proof gaps, and exact next tools/UI steps.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "data-explorer",
    "Discover what data is available in this iMIS instance",
    {},
    () => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Help me explore what data is available in this iMIS instance:
1. Use imis_entity_types to list all entity types and categories.
2. For key entities (Party, Event, Subscription, Group, Item), use imis_entity_schema to show their field structures.
3. Try imis_panel_data to see if there are custom panel sources with additional data.
4. Provide an organized summary of:
   - How many entity types are available by category
   - Key entities and what they represent
   - Any custom panel sources found
   - Suggestions for useful IQA query paths to explore`)
          }
        }
      ]
    })
  );
}

// src/prompts/content-prompts.ts
function registerContentPrompts(server) {
  server.prompt(
    "site-explorer",
    "Explore the iMIS site structure, content records, and document tree",
    {},
    () => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Help me explore the iMIS site structure and content:
1. Use imis_content_discovery first to identify native RiSE Perspective/site records, website keys, content roots, navigation roots, member portal/microsite scopes, and unassigned NAV rows.
2. Use imis_document_browse to list the selected content root from discovery, or '@/' when no site scope is known.
3. Browse key folders:
   - '@/Shared Content/' for peripheral custom/proof content when present
   - '@/iCore/Content/' for system/sample content pages to inspect, not as a default write target
   - '$/Common/Queries/' for system IQA queries
4. For interesting content records, use imis_document_get to see the full document data.
5. For content pages, use imis_page_iparts action="inspect" when XML-aware iPart detail is needed; use imis_content_items for lighter metadata.
6. Use imis_entity_list BOEntityDefinition to discover available business objects.
7. When a page or iPart should be driven by custom BO/panel data, use imis_iqa_content_plan to produce the query/content/iPart contract before writing.
8. Summarize: Perspective/site scopes, contentRoots, navigationRoots, unassigned navigation, content pages, available IQA queries, key business objects, and exact next safe action.`)
          }
        }
      ]
    })
  );
  server.prompt(
    "content-manager",
    "Create or manage content in iMIS",
    {
      path: external_exports.string().optional().describe("Document System path to work with (e.g., '@/Shared Content/Codex Work/')"),
      action: external_exports.enum(["create", "update", "browse"]).optional().describe("What to do: create new content, update existing, or browse")
    },
    ({ path: path3, action }) => {
      const targetPath = path3 ?? "@/Shared Content/Codex Work/";
      const op = action ?? "browse";
      const steps = [];
      if (op === "browse" || op === "update") {
        steps.push(
          `1. Use imis_content_discovery when site/microsite/member portal/navigation ownership matters, then use imis_document_browse with path="${targetPath}" or the discovered content root to list existing content.`
        );
      }
      if (op === "create") {
        steps.push(
          `1. Use imis_content_discovery when creating under an existing site, microsite, member portal, or navigation scope; carry perspectiveName, websiteKey, contentRoots, and navigationRoots forward.`
        );
        steps.push(
          `2. Use imis_document_browse with path="${targetPath}" or the discovered target content root to see existing content in the target location.`
        );
        steps.push(
          `3. If the page is query-backed or custom-panel-backed, use imis_iqa_content_plan before choosing the IQD and iPart shape.`
        );
        steps.push(
          `4. If this is a cart checkout or order-confirmation page set, use imis_cart_checkout_pages instead of raw typed iPart XML. It assembles the native checkout iPart set and returns the publish/navigation handoff; order, payment, refund, receipt, and AutoPay behavior still belong to their separate commerce/finance tools.`
        );
        steps.push(
          `5. If this is a recurring donation/Give Now page, use imis_recurring_donation_pages instead of raw typed iPart XML. It assembles the native iMIS recurring donation iPart chain, not a custom iPart; mandate creation, initial payment, invoice generation, and collection still require hosted checkout plus AutoPay/payment readback.`
        );
        steps.push(
          `6. If this is a multi-page section, navigation-aware section, or iPart-heavy content set, use imis_dashboard_pages with a pages/iParts/navigation JSON spec so the agent gets one delivery packet. Pick a content root that belongs to the intended website/sitemap branch; a raw @/ proof-folder page can render without the staff/site shell even when the ~/ NAV record exists. If NAV returns api_created_orphan_without_hierarchy, treat the returned native Site Builder packet as the required next action rather than claiming sidebar placement. If the layout is novel, include a stable customLayout with reuseExisting=true or create it first with imis_content_layouts instead of copying a native dashboard preset or generating a new timestamped layout each run.`
        );
        steps.push(
          `7. Otherwise use imis_document_create to create a new content record or folder at "${targetPath}".`
        );
        steps.push(
          `8. After creation, request publish only when explicitly asked. imis_document_update status="Published" returns/forwards the native publish intervention by default; AgentZ/browser automation is a valid agent path when connected, but do not claim live until a follow-up status check verifies Published.`
        );
      }
      if (op === "update") {
        steps.push(
          `2. Ask which document to update, then use imis_document_get or imis_page_iparts action="inspect" to retrieve the exact current state.`
        );
        steps.push(
          `3. Keep backupBeforeWrite enabled on mutating primitives. imis_document_update, imis_page_iparts, and layout replacement return compact backup metadata; keep that backupRef in the final packet.`
        );
        steps.push(
          `4. Use the narrowest writer: imis_document_update for metadata/Data, imis_page_iparts for iParts, imis_content_layouts for LAY, imis_navigation_items for NAV, or imis_iqd_query for IQD.`
        );
        steps.push(
          `5. Verify with imis_document_get, imis_page_iparts action="inspect", imis_navigation_items action="inspect", imis_public_sitemap_audit mode="validate", or imis_rendered_page_audit when the page is routable through AgentZ. For staff pages, verify the ~/ sitemap route renders header/sidebar; the raw @/ publish URL is not sufficient proof.`
        );
      }
      steps.push(
        `${steps.length + 1}. Confirm the operation was successful and show the results.`
      );
      return {
        messages: [
          {
            role: "user",
            content: {
              type: "text",
              text: withCoworkInlinePresentation(`Help me ${op} iMIS content at "${targetPath}".

Steps:
${steps.join("\n")}`)
            }
          }
        ]
      };
    }
  );
  server.prompt(
    "query-explorer",
    "Explore and run IQA queries available in this iMIS instance",
    {
      queryPath: external_exports.string().optional().describe("Specific query path to explore (e.g., '$/Common/Queries/ContactManagement/')")
    },
    ({ queryPath }) => ({
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: withCoworkInlinePresentation(`Help me explore IQA queries in this iMIS instance${queryPath ? ` starting at "${queryPath}"` : ""}:
1. ${queryPath ? `Use imis_document_browse with path="${queryPath}" to list queries in this folder.` : `Use imis_document_browse with path="$/Common/Queries/" to list system query folders.`}
2. Browse interesting query folders to find available reports.
3. For promising queries, use imis_query to execute them and see the data they return.
4. If a query has too many results, add limit=10 to preview the data.
5. Summarize: what query folders exist, what reports are available, which queries are REST-enabled.
6. Suggest useful queries for common tasks (member reports, financial summaries, event analytics).`)
          }
        }
      ]
    })
  );
}

